<template><div class="overlay"><form class="dialog" @submit.prevent="start"><header><h3>{{t('promptops.evaluations.configuration')}}</h3><button type="button" @click="$emit('close')">×</button></header><p v-if="error" class="error">{{error}}</p><label>{{t('promptops.evaluations.dataset')}}<input :value="dataset.name" disabled></label><label>{{t('promptops.evaluations.selectPrompt')}}<select v-model="promptId" required @change="loadVersions"><option value="" disabled>—</option><option v-for="item in prompts" :key="item.id" :value="item.id">{{item.name}} · {{item.currentVersion}}</option></select></label><label>{{t('promptops.evaluations.selectVersion')}}<select v-model="versionId" required><option v-for="item in versions" :key="item.id" :value="item.id">{{item.versionNumber}} · {{item.changeSummary}}</option></select></label><label>{{t('promptops.evaluations.selectModel')}}<select v-model="modelKey" required><option v-for="item in models" :key="item.configKey" :value="item.configKey">{{item.displayName}} · {{item.providerId}} / {{item.modelId}}</option></select></label><p v-if="!models.length" class="notice">{{t('promptops.evaluations.noEnabledModels')}}</p><fieldset><legend>{{t('promptops.evaluations.testCaseSelection')}}</legend><label><input v-model="selection" type="radio" value="all"> {{t('promptops.evaluations.allCases')}}</label><label><input v-model="selection" type="radio" value="selected" :disabled="!selectedIds.length"> {{t('promptops.evaluations.selectedCases')}} ({{selectedIds.length}})</label><label><input v-model="selection" type="radio" value="tag"> {{t('promptops.evaluations.filterByTag')}} <input v-model="tag" :disabled="selection!=='tag'"></label></fieldset><div class="grid"><label>{{t('promptops.evaluations.temperature')}}<input v-model.number="temperature" type="number" min="0" max="2" step="0.1"></label><label>{{t('promptops.evaluations.maxTokens')}}<input v-model.number="maxTokens" type="number" min="1"></label><label>{{t('promptops.evaluations.concurrency')}}<input v-model.number="concurrency" type="number" min="1" max="10"></label></div><section class="summary"><strong>{{t('promptops.evaluations.summary')}}</strong><span>{{estimatedCases}} {{t('promptops.datasets.testCases')}}</span><span>{{t('promptops.evaluations.pricingUnavailable')}}</span></section><footer><button type="button" @click="$emit('close')">{{t('promptops.common.cancel')}}</button><button type="submit" :disabled="starting||!canStart">{{starting?t('promptops.evaluations.running'):t('promptops.evaluations.start')}}</button></footer></form></div></template>
<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{useI18n}from'vue-i18n';import{listEnabledModelOptions,type Dataset,type DatasetTestCase,type EnabledModelOption,type PromptOpsPrompt,type PromptOpsPromptVersion}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../../services/promptops';const props=defineProps<{dataset:Dataset;testCases:DatasetTestCase[];selectedIds:string[]}>(),emit=defineEmits<{close:[];started:[id:string]}>(),{t}=useI18n(),services=usePromptOpsServices();const prompts=ref<PromptOpsPrompt[]>([]),versions=ref<PromptOpsPromptVersion[]>([]),models=ref<EnabledModelOption[]>([]),promptId=ref(''),versionId=ref(''),modelKey=ref(''),selection=ref<'all'|'selected'|'tag'>(props.selectedIds.length?'selected':'all'),tag=ref(''),temperature=ref(.2),maxTokens=ref(500),concurrency=ref(2),starting=ref(false),error=ref('');const selectedCases=computed(()=>selection.value==='selected'?props.testCases.filter(item=>props.selectedIds.includes(item.id)):selection.value==='tag'?props.testCases.filter(item=>item.tags?.includes(tag.value)):props.testCases),estimatedCases=computed(()=>selectedCases.value.length),canStart=computed(()=>promptId.value&&versionId.value&&modelKey.value&&estimatedCases.value>0&&concurrency.value>=1&&concurrency.value<=10);const loadVersions=async()=>{versions.value=promptId.value?await services.promptVersionRepository.listByPromptId(promptId.value):[];const prompt=prompts.value.find(item=>item.id===promptId.value);versionId.value=versions.value.find(item=>item.versionNumber===prompt?.currentVersion)?.id??versions.value[0]?.id??''};onMounted(async()=>{try{prompts.value=(await services.promptRepository.list({workspaceId:props.dataset.workspaceId})).filter(item=>item.status!=='archived');models.value=await listEnabledModelOptions(services.modelManager);promptId.value=prompts.value[0]?.id??'';modelKey.value=models.value[0]?.configKey??'';await loadVersions()}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}});const start=async()=>{if(!canStart.value)return;starting.value=true;error.value='';try{const model=models.value.find(item=>item.configKey===modelKey.value)!;const run=await services.batchEvaluationService.start({workspaceId:props.dataset.workspaceId,datasetId:props.dataset.id,promptId:promptId.value,promptVersionId:versionId.value,modelConfigKey:model.configKey,providerId:model.providerId,modelId:model.modelId,selectedTestCaseIds:selection.value==='all'?undefined:selectedCases.value.map(item=>item.id),tag:selection.value==='tag'?tag.value:undefined,temperature:temperature.value,maxTokens:maxTokens.value,concurrency:concurrency.value});emit('started',run.id)}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{starting.value=false}}</script>
<style scoped>.overlay{position:fixed;inset:0;background:#0008;display:grid;place-items:center;z-index:50}.dialog{width:min(680px,92vw);max-height:90vh;overflow:auto;background:white;color:#111827;border-radius:12px;padding:22px;display:grid;gap:14px}header,footer,.grid,.summary{display:flex;gap:12px}header{justify-content:space-between}.dialog label{display:grid;gap:5px}.dialog input,.dialog select,.dialog button{padding:9px;border:1px solid #cbd5e1;border-radius:7px}.grid>*{flex:1}.summary{justify-content:space-between;padding:12px;background:#f1f5f9}.error{color:#b91c1c}.notice{color:#92400e}footer{justify-content:flex-end}</style>
